from __future__ import annotations
from html import escape
from pathlib import Path
import pandas as pd

def pct(v,s=False):
    if pd.isna(v):return "—"
    n=100*float(v);return f"{n:+.1f}%" if s else f"{n:.1f}%"
def num(v,d=2):return "—" if pd.isna(v) else f"{float(v):.{d}f}"
def odds(v):
    if pd.isna(v):return "—"
    n=int(round(float(v)));return f"+{n}" if n>0 else str(n)
def time_et(v):
    if pd.isna(v):return "Time TBD"
    t=pd.Timestamp(v);t=t.tz_localize("UTC") if t.tzinfo is None else t
    return t.tz_convert("America/New_York").strftime("%-I:%M %p ET")
def card(r):
    sig=str(r.get("signal","PASS"));css="value" if sig=="HR VALUE" else ("watch" if sig=="HR WATCH" else "pass")
    pa=int(float(r.get("bvp_pa",0) or 0));hr=int(float(r.get("bvp_hr",0) or 0));order=int(float(r.get("batting_order",9)))
    market="" if pd.isna(r.get("over_odds")) else f'<div class="market"><div><small>Sportsbook HR</small><strong>{odds(r.get("over_odds"))}</strong><i>{escape(str(r.get("over_book") or "—"))}</i></div><div><small>No-vig / edge</small><strong>{pct(r.get("over_no_vig_probability"))}</strong><i>{pct(r.get("market_edge"),True)}</i></div><div><small>Expected value</small><strong>{pct(r.get("ev_per_unit"),True)}</strong><i>per unit</i></div></div>'
    search=escape(f'{r.get("player_name","")} {r.get("away_team","")} {r.get("home_team","")}'.lower())
    return f'''<article class="card" data-signal="{sig}" data-search="{search}" data-prob="{float(r.get('home_run_probability',0)):.8f}" data-bvp="{pa}"><div class="top"><div><h2>{escape(str(r.get('player_name','Unknown')))}</h2><span>{escape(str(r.get('away_team','—')))} @ {escape(str(r.get('home_team','—')))} · {time_et(r.get('game_datetime'))}</span></div><b class="{css}">{escape(sig)}</b></div><p>Confirmed · batting {order}</p><div class="prob"><small>Home-run probability</small><strong>{pct(r.get('home_run_probability'))}</strong><i>{odds(r.get('fair_odds'))} fair</i></div><div class="grid"><div><small>Barrels / PA</small><strong>{pct(r.get('batter_barrel_pa_long'))}</strong><i>recent {pct(r.get('batter_barrel_pa_recent'))}</i></div><div><small>Hard air / PA</small><strong>{pct(r.get('batter_hard_air_pa_long'))}</strong><i>EV90 {num(r.get('batter_ev90_long'),1)} mph</i></div><div><small>Pitcher HR / BF</small><strong>{pct(r.get('pitcher_hr_bf'))}</strong><i>barrel/BF {pct(r.get('pitcher_barrel_bf'))}</i></div><div><small>Environment</small><strong>{num(r.get('park_hr_factor'),2)}×</strong><i>{num(r.get('temperature_f'),0)}°F · wind {num(r.get('wind_speed_mph'),0)} mph</i></div></div><div class="bvp"><div><small>History vs starter</small><strong>{pa} PA · {hr} HR</strong></div><div><small>Shrunk BvP HR rate</small><strong>{pct(r.get('bvp_hr_shrunk'))}</strong><i>reliability {pct(r.get('bvp_reliability'))}</i></div></div>{market}</article>'''
def render_home_run_dashboard(rows,metrics,output_path,title="MLB Home Run Probability"):
    out=Path(output_path);out.parent.mkdir(parents=True,exist_ok=True);g=metrics.get("generated_at_utc");gl=pd.Timestamp(g).tz_convert("America/New_York").strftime("%B %-d, %-I:%M %p ET") if g else "Not generated";dl=pd.Timestamp(metrics.get("projection_date")).strftime("%B %-d, %Y") if metrics.get("projection_date") else "Current slate"
    values=int(rows.signal.eq("HR VALUE").sum()) if not rows.empty else 0;watches=int(rows.signal.eq("HR WATCH").sum()) if not rows.empty else 0;bvp=int(pd.to_numeric(rows.get("bvp_pa"),errors="coerce").ge(5).sum()) if not rows.empty else 0;cards="".join(card(r) for _,r in rows.iterrows()) or '<section class="empty"><h2>No confirmed HR candidates</h2><p>The board appears after MLB posts lineups and probable starters.</p></section>'
    note="Sportsbook HR prices are connected. HR VALUE requires positive no-vig edge and expected value." if metrics.get("market_odds_available") else "Model probabilities and fair odds are active. Sportsbook value appears when HR prices are available."
    html=f'''<!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>{escape(title)}</title><style>:root{{--bg:#090b0f;--p:#171e29;--t:#f5f7fa;--m:#9da8b7;--l:#2a3442;--g:#66e08d;--a:#f3bd54}}*{{box-sizing:border-box}}body{{margin:0;background:radial-gradient(circle at 15% 0%,#242014,var(--bg) 36rem);color:var(--t);font-family:Arial,sans-serif}}main{{max-width:980px;margin:auto;padding:24px 15px 50px}}h1{{font-size:clamp(2.2rem,9vw,4.5rem);line-height:.9;text-transform:uppercase;margin:14px 0}}.badge{{color:var(--a);font-size:.72rem;font-weight:700;text-transform:uppercase}}.sub,.notice,p,small,i,footer{{color:var(--m);font-size:.75rem}}.notice{{border:1px solid #5b4b2d;background:#241f15;padding:11px;border-radius:12px;margin:16px 0}}nav,.filters{{display:flex;gap:8px;overflow-x:auto}}nav a,button{{color:var(--t);background:#151c26;border:1px solid var(--l);padding:9px 11px;border-radius:10px;text-decoration:none;white-space:nowrap}}.summary,.grid,.market,.bvp{{display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin:12px 0}}.summary div,.grid div,.market div,.bvp div,.prob{{background:#0f141c;border:1px solid var(--l);border-radius:11px;padding:10px}}.controls{{position:sticky;top:0;background:#090b0ff2;padding:10px 0;z-index:2}}input{{width:100%;margin-top:8px;background:#0e141c;border:1px solid var(--l);color:var(--t);border-radius:10px;padding:10px}}button.active{{color:var(--a);border-color:var(--a)}}.card,.empty{{background:linear-gradient(145deg,#1b232f,#121720);border:1px solid var(--l);border-radius:16px;padding:15px;margin:12px 0}}.top{{display:flex;justify-content:space-between;gap:10px}}h2{{margin:0}}.top b{{border:1px solid;border-radius:999px;padding:6px 8px;height:max-content;font-size:.68rem}}.value{{color:var(--g)}}.watch{{color:var(--a)}}.pass{{color:#bdc4ce}}.prob strong{{display:block;color:var(--g);font-size:2.2rem}}.bvp{{grid-template-columns:repeat(2,1fr)}}.market{{grid-template-columns:repeat(3,1fr)}}strong{{display:block}}i{{font-style:normal}}[hidden]{{display:none!important}}@media(max-width:700px){{.summary,.grid{{grid-template-columns:repeat(2,1fr)}}}}@media(max-width:520px){{.market,.bvp{{grid-template-columns:1fr}}}}</style></head><body><main><span class="badge">Stage 4 · dedicated HR classifier</span><h1>{escape(title)}</h1><div class="sub">{dl} · generated {gl}<br>Brier {num(metrics.get('brier_score'),3)} · log loss {num(metrics.get('log_loss'),3)} · ROC AUC {num(metrics.get('roc_auc'),3)}</div><div class="notice">{note}</div><nav><a href="index.html">Game Board</a><a href="props.html">All Props</a><a href="home_run_probabilities.csv">HR CSV</a><a href="home_run_metrics.json">Metrics</a></nav><div class="summary"><div><small>Confirmed hitters</small><strong>{len(rows)}</strong></div><div><small>HR values</small><strong>{values}</strong></div><div><small>HR watches</small><strong>{watches}</strong></div><div><small>BvP ≥ 5 PA</small><strong>{bvp}</strong></div></div><div class="controls"><div class="filters"><button data-f="all">All</button><button data-f="value">HR Values</button><button data-f="watch">HR Watches</button><button data-f="bvp">BvP History</button></div><input id="s" placeholder="Search player or team"></div><div id="cards">{cards}</div><footer>BvP history is shifted to pregame and Bayesian-shrunk toward league rates; small samples cannot dominate the result.</footer></main><script>(()=>{{const cs=[...document.querySelectorAll('.card')],bs=[...document.querySelectorAll('button')],s=document.getElementById('s');let f='all';function a(){{let q=s.value.toLowerCase();cs.forEach(c=>{{let ok=!q||c.dataset.search.includes(q);if(f==='value')ok=ok&&c.dataset.signal==='HR VALUE';if(f==='watch')ok=ok&&c.dataset.signal==='HR WATCH';if(f==='bvp')ok=ok&&+c.dataset.bvp>=5;c.hidden=!ok}})}}bs.forEach(b=>b.onclick=()=>{{f=b.dataset.f;bs.forEach(x=>x.classList.toggle('active',x===b));a()}});s.oninput=a;bs[0]?.classList.add('active');a()}})()</script></body></html>'''
    out.write_text(html,encoding="utf-8");return out
